// Correct way to create and show a widget
void AMyHUD::BeginPlay() {
    Super::BeginPlay();
    if (MainWidgetClass) {
        MainWidget = CreateWidget<UUserWidget>(GetOwningPlayerController(), MainWidgetClass);
        if (MainWidget) {
            MainWidget->AddToViewport(0);
        }
    }
}

// BAD - polling binding (expensive, can be stale)
// In UMG: Bind Text to 'GetHealthText' function

// GOOD - event-driven update
void UMyHealthWidget::SetHealth(float NewHealth) {
    HealthText->SetText(FText::AsNumber(NewHealth));
    HealthBar->SetPercent(NewHealth / MaxHealth);
}

// Called from the character when health changes
void AMyCharacter::OnHealthChanged(float NewHealth) {
    if (HealthWidget) HealthWidget->SetHealth(NewHealth);
}
